+
+const isNonEmptyString = (value: unknown): value is string =>
+  typeof value === "string" && value.trim().length > 0;
+
+const getBookmarkById = (id: number): Bookmark | undefined =>
+  db
+    .prepare("SELECT id, url, title, description, created_at, updated_at FROM bookmarks WHERE id = ?")
+    .get(id) as Bookmark | undefined;
+
+const parseBookmarkId = (value: string): number | null => {
+  const id = Number(value);
+  return Number.isInteger(id) && id > 0 ? id : null;
+};
+
+app.post("/bookmarks", (req, res) => {
+  const { url, title, description } = req.body ?? {};
+
+  if (!isNonEmptyString(url)) {
+    return res.status(400).json({ error: "url is required" });
+  }
+
+  if (!isNonEmptyString(title)) {
+    return res.status(400).json({ error: "title is required" });
+  }
+
+  const now = new Date().toISOString();
+  const result = db
+    .prepare(
+      `INSERT INTO bookmarks (url, title, description, created_at, updated_at)
+       VALUES (?, ?, ?, ?, ?)`
+    )
+    .run(
+      url.trim(),
+      title.trim(),
+      typeof description === "string" ? description : null,
+      now,
+      now
+    );
+
+  const bookmark = getBookmarkById(Number(result.lastInsertRowid));
+  return res.status(201).json(bookmark);
+});
+
+app.get("/bookmarks", (_req, res) => {
+  const bookmarks = db
+    .prepare("SELECT id, url, title, description, created_at, updated_at FROM bookmarks ORDER BY id")
+    .all() as Bookmark[];
+
+  res.status(200).json(bookmarks);
+});
+
+app.get("/bookmarks/:id", (req, res) => {
+  const id = parseBookmarkId(req.params.id);
+
+  if (id === null) {
+    return res.status(404).json({ error: "bookmark not found" });
+  }
+
+  const bookmark = getBookmarkById(id);
+
+  if (!bookmark) {
+    return res.status(404).json({ error: "bookmark not found" });
+  }
+
+  return res.status(200).json(bookmark);
+});
+
+app.put("/bookmarks/:id", (req, res) => {
+  const id = parseBookmarkId(req.params.id);
+  const existingBookmark = id === null ? undefined : getBookmarkById(id);
+
+  if (id === null || !existingBookmark) {
+    return res.status(404).json({ error: "bookmark not found" });
+  }
+
+  const { url, title, description } = req.body ?? {};
+
+  if (url !== undefined && !isNonEmptyString(url)) {
+    return res.status(400).json({ error: "url must be a non-empty string" });
+  }
+
+  if (title !== undefined && !isNonEmptyString(title)) {
+    return res.status(400).json({ error: "title must be a non-empty string" });
+  }
+
+  const now = new Date().toISOString();
+  db.prepare(
+    `UPDATE bookmarks
+     SET url = COALESCE(?, url),
+         title = COALESCE(?, title),
+         description = ?,
+         updated_at = ?
+     WHERE id = ?`
+  ).run(
+    typeof url === "string" ? url.trim() : null,
+    typeof title === "string" ? title.trim() : null,
+    description === undefined
+      ? existingBookmark.description
+      : typeof description === "string"
+        ? description
+        : null,
+    now,
+    id
+  );
+
+  return res.status(200).json(getBookmarkById(id));
+});
+
+app.delete("/bookmarks/:id", (req, res) => {
+  const id = parseBookmarkId(req.params.id);
+
+  if (id === null) {
+    return res.status(404).json({ error: "bookmark not found" });
+  }
+
+  const result = db.prepare("DELETE FROM bookmarks WHERE id = ?").run(id);
+
+  if (result.changes === 0) {
+    return res.status(404).json({ error: "bookmark not found" });
+  }
+
+  return res.status(204).send();
+});

